import Foundation

// ChargeCtrlPolicy 인코딩 테스트 (쓰기는 하지 않고, 기존 데이터와 비교만)
class ChargePolicy: NSObject, NSCoding {
    var reason: String
    var owner: Int
    var soclimit: Int
    var drain: Bool
    var terminated: Bool
    var noChargeToFull: Bool
    var isEndOfCharge: Bool
    var token: UUID

    init(reason: String, owner: Int, soclimit: Int, drain: Bool, terminated: Bool, noChargeToFull: Bool, isEndOfCharge: Bool, token: UUID) {
        self.reason = reason
        self.owner = owner
        self.soclimit = soclimit
        self.drain = drain
        self.terminated = terminated
        self.noChargeToFull = noChargeToFull
        self.isEndOfCharge = isEndOfCharge
        self.token = token
    }

    required init?(coder: NSCoder) {
        reason = (coder.decodeObject(forKey: "reason") as? String) ?? ""
        owner = coder.decodeInteger(forKey: "owner")
        soclimit = coder.decodeInteger(forKey: "soclimit")
        drain = coder.decodeBool(forKey: "drain")
        terminated = coder.decodeBool(forKey: "terminated")
        noChargeToFull = coder.decodeBool(forKey: "noChargeToFull")
        isEndOfCharge = coder.decodeBool(forKey: "isEndOfCharge")
        token = (coder.decodeObject(forKey: "token") as? UUID) ?? UUID()
    }

    func encode(with coder: NSCoder) {
        coder.encode(reason, forKey: "reason")
        coder.encode(owner, forKey: "owner")
        coder.encode(soclimit, forKey: "soclimit")
        coder.encode(drain, forKey: "drain")
        coder.encode(terminated, forKey: "terminated")
        coder.encode(noChargeToFull, forKey: "noChargeToFull")
        coder.encode(isEndOfCharge, forKey: "isEndOfCharge")
        coder.encode(token, forKey: "token")
    }
}

// 1. 현재 plist 읽기
let plistPath = "/Library/Preferences/com.apple.powerd.charging.plist"
guard let data = FileManager.default.contents(atPath: plistPath),
      let plist = try? PropertyListSerialization.propertyList(from: data, format: nil) as? [String: Any],
      let originalPoliciesData = plist["policies"] as? Data else {
    print("ERROR: Cannot read policies"); exit(1)
}

// 2. 동일한 값으로 새로 인코딩
NSKeyedArchiver.setClassName("ChargeCtrlPolicy", for: ChargePolicy.self)

let policy = ChargePolicy(
    reason: "manualChargeLimit",
    owner: 177,
    soclimit: 80,
    drain: true,
    terminated: false,
    noChargeToFull: false,
    isEndOfCharge: true,
    token: UUID(uuidString: "1B6274D3-EB56-42E4-AAAC-29C1F20A2E9D")!
)

let policies: [ChargePolicy] = [policy]

do {
    let encodedData = try NSKeyedArchiver.archivedData(withRootObject: policies, requiringSecureCoding: false)
    print("Original data: \(originalPoliciesData.count) bytes")
    print("Encoded data:  \(encodedData.count) bytes")
    print("Match: \(originalPoliciesData == encodedData)")

    // 100%로 변경한 버전도 생성해서 테스트
    let policy100 = ChargePolicy(
        reason: "manualChargeLimit",
        owner: 177,
        soclimit: 100,
        drain: true,
        terminated: false,
        noChargeToFull: false,
        isEndOfCharge: true,
        token: UUID()
    )
    let data100 = try NSKeyedArchiver.archivedData(withRootObject: [policy100], requiringSecureCoding: false)
    print("\n100% policy encoded: \(data100.count) bytes")

    // 디코딩 검증
    NSKeyedUnarchiver.setClass(ChargePolicy.self, forClassName: "ChargeCtrlPolicy")
    let unarchiver = try NSKeyedUnarchiver(forReadingFrom: data100)
    unarchiver.requiresSecureCoding = false
    unarchiver.setClass(ChargePolicy.self, forClassName: "ChargeCtrlPolicy")
    if let decoded = unarchiver.decodeObject(forKey: NSKeyedArchiveRootObjectKey) as? [ChargePolicy] {
        print("Decoded soclimit: \(decoded[0].soclimit)")
        print("Round-trip OK!")
    }
    unarchiver.finishDecoding()

    // /tmp에 테스트 plist 생성 (실제 시스템에는 쓰지 않음)
    var newPlist: [String: Any] = plist
    newPlist["policies"] = data100
    let newPlistData = try PropertyListSerialization.data(fromPropertyList: newPlist, format: .binary, options: 0)
    try newPlistData.write(to: URL(fileURLWithPath: "/tmp/test_charging_100.plist"))
    print("\nTest plist written to /tmp/test_charging_100.plist")

} catch {
    print("Error: \(error)")
}

